%% plot_c6_c8_matlab.m
% Plot C6-C8 violation rates for two stress dimensions:
% 1) scenario = user_num
% 2) scenario = f_scale
% Input file expected: new_simulation/results_paper_c5/stress_scan_summary.csv

clear; clc; close all;

%% Paths
thisFileDir = fileparts(mfilename('fullpath'));
inputCsv = fullfile(thisFileDir, 'results_paper_c5', 'stress_scan_summary.csv');
outDir = fullfile(thisFileDir, 'figures_paper_c5');

if ~isfile(inputCsv)
    error('Input CSV not found: %s', inputCsv);
end
if ~isfolder(outDir)
    mkdir(outDir);
end

%% Load and sanitize table
T = readtable(inputCsv, 'TextType', 'string');

requiredCols = ["scenario","value","policy", ...
    "p_c6_viol_mean","p_c7_viol_mean","p_c8_viol_mean"];
for i = 1:numel(requiredCols)
    if ~ismember(requiredCols(i), T.Properties.VariableNames)
        error('Missing required column: %s', requiredCols(i));
    end
end

% Convert numeric-like columns safely
numCols = ["value","p_c6_viol_mean","p_c7_viol_mean","p_c8_viol_mean"];
for i = 1:numel(numCols)
    c = numCols(i);
    if ~isnumeric(T.(c))
        T.(c) = str2double(string(T.(c)));
    end
end

% Drop rows with missing key values
valid = ~ismissing(T.scenario) & ~ismissing(T.policy) & ...
        ~isnan(T.value) & ~isnan(T.p_c6_viol_mean) & ...
        ~isnan(T.p_c7_viol_mean) & ~isnan(T.p_c8_viol_mean);
T = T(valid, :);

%% Aggregate duplicates by (scenario, value, policy)
G = groupsummary(T, {'scenario','value','policy'}, 'mean', ...
    {'p_c6_viol_mean','p_c7_viol_mean','p_c8_viol_mean'});

% Rename grouped columns for easier access
G.Properties.VariableNames{'mean_p_c6_viol_mean'} = 'p_c6';
G.Properties.VariableNames{'mean_p_c7_viol_mean'} = 'p_c7';
G.Properties.VariableNames{'mean_p_c8_viol_mean'} = 'p_c8';

%% Plot helper settings
metricNames = {'p_c6','p_c7','p_c8'};
metricLabels = {'C6 violation rate','C7 violation rate','C8 violation rate'};
scenarioList = {'user_num','f_scale'};
outNames = {'c6_c8_vs_user_num.png','c6_c8_vs_f_scale.png'};

for s = 1:numel(scenarioList)
    sc = scenarioList{s};
    S = G(G.scenario == sc, :);
    if isempty(S)
        warning('No rows found for scenario=%s. Skip plotting.', sc);
        continue;
    end

    % Sort values and policies for stable visuals
    xVals = unique(S.value);
    xVals = sort(xVals);
    policies = unique(S.policy);
    policies = sort(policies);

    % Style map
    nP = numel(policies);
    cmap = lines(max(nP, 7));
    mk = {'o','s','d','^','v','>','<','p','h','x','+'};

    fig = figure('Color','w', 'Position', [100 100 1400 420]);
    tl = tiledlayout(1, 3, 'Padding', 'compact', 'TileSpacing', 'compact');
    title(tl, sprintf('Violation Rates under scenario = %s', sc), ...
        'FontWeight', 'bold', 'FontSize', 13);

    for m = 1:3
        nexttile; hold on; grid on; box on;
        yField = metricNames{m};

        for p = 1:nP
            pol = policies(p);
            P = S(S.policy == pol, :);
            [~, ord] = sort(P.value);
            Px = P.value(ord);
            Py = P.(yField)(ord);

            plot(Px, Py, 'LineWidth', 1.8, ...
                'Color', cmap(p,:), ...
                'Marker', mk{mod(p-1, numel(mk))+1}, ...
                'MarkerSize', 6, ...
                'DisplayName', char(pol));
        end

        xlabel(sc, 'FontSize', 11);
        ylabel(metricLabels{m}, 'FontSize', 11);
        ylim([0, 1]);
        xlim([min(xVals), max(xVals)]);
        title(metricLabels{m}, 'FontWeight', 'bold');
    end

    lgd = legend('Location','southoutside', 'NumColumns', min(4, nP));
    lgd.Box = 'off';

    outPath = fullfile(outDir, outNames{s});
    exportgraphics(fig, outPath, 'Resolution', 300);
    fprintf('Saved: %s\n', outPath);
end

fprintf('Done.\n');
